func (o *Repository) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "CreatedByUserAccount":
		rel, ok := retrieved.(*UserAccount)
		if !ok {
			return fmt.Errorf("repository cannot load %T as %q", retrieved, name)
		}

		o.R.CreatedByUserAccount = rel

		if rel != nil {
			rel.R.CreatedByRepositories = RepositorySlice{o}
		}
		return nil
	case "Organization":
		rel, ok := retrieved.(*Organization)
		if !ok {
			return fmt.Errorf("repository cannot load %T as %q", retrieved, name)
		}

		o.R.Organization = rel

		if rel != nil {
			rel.R.Repositories = RepositorySlice{o}
		}
		return nil
	case "UpdatedByUserAccount":
		rel, ok := retrieved.(*UserAccount)
		if !ok {
			return fmt.Errorf("repository cannot load %T as %q", retrieved, name)
		}

		o.R.UpdatedByUserAccount = rel

		if rel != nil {
			rel.R.UpdatedByRepositories = RepositorySlice{o}
		}
		return nil
	case "RepositoryPersonalAccessTokens":
		rels, ok := retrieved.(RepositoryPersonalAccessTokenSlice)
		if !ok {
			return fmt.Errorf("repository cannot load %T as %q", retrieved, name)
		}

		o.R.RepositoryPersonalAccessTokens = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Repository = o
			}
		}
		return nil
	default:
		return fmt.Errorf("repository has no relationship %q", name)
	}
}

