type repositoryJoins[Q dialect.Joinable] struct {
	typ                            string
	CreatedByUserAccount           modAs[Q, userAccountColumns]
	Organization                   modAs[Q, organizationColumns]
	UpdatedByUserAccount           modAs[Q, userAccountColumns]
	RepositoryPersonalAccessTokens modAs[Q, repositoryPersonalAccessTokenColumns]
}

func (j repositoryJoins[Q]) aliasedAs(alias string) repositoryJoins[Q] {
	return buildRepositoryJoins[Q](buildRepositoryColumns(alias), j.typ)
}

func buildRepositoryJoins[Q dialect.Joinable](cols repositoryColumns, typ string) repositoryJoins[Q] {
	return repositoryJoins[Q]{
		typ: typ,
		CreatedByUserAccount: modAs[Q, userAccountColumns]{
			c: UserAccounts.Columns,
			f: func(to userAccountColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, UserAccounts.Name().As(to.Alias())).On(
						to.ID.EQ(cols.CreatedBy),
					))
				}

				return mods
			},
		},
		Organization: modAs[Q, organizationColumns]{
			c: Organizations.Columns,
			f: func(to organizationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Organizations.Name().As(to.Alias())).On(
						to.ID.EQ(cols.OrganizationID),
					))
				}

				return mods
			},
		},
		UpdatedByUserAccount: modAs[Q, userAccountColumns]{
			c: UserAccounts.Columns,
			f: func(to userAccountColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, UserAccounts.Name().As(to.Alias())).On(
						to.ID.EQ(cols.UpdatedBy),
					))
				}

				return mods
			},
		},
		RepositoryPersonalAccessTokens: modAs[Q, repositoryPersonalAccessTokenColumns]{
			c: RepositoryPersonalAccessTokens.Columns,
			f: func(to repositoryPersonalAccessTokenColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, RepositoryPersonalAccessTokens.Name().As(to.Alias())).On(
						to.RepositoryID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
